package ccxt

type Lighter struct {
	*LighterCore
	Core          *LighterCore
	exchangeTyped *ExchangeTyped
}

func NewLighter(userConfig map[string]interface{}) *Lighter {
	p := NewLighterCore()
	p.Init(userConfig)
	return &Lighter{
		LighterCore:   p,
		Core:          p,
		exchangeTyped: NewExchangeTyped(&p.Exchange),
	}
}
func NewLighterFromCore(core *LighterCore) *Lighter {
	return &Lighter{
		LighterCore:   core,
		Core:          core,
		exchangeTyped: NewExchangeTyped(&core.Exchange),
	}
}

